 186→router.get('/getFollowsData', async(req, res) => {
 187→    const {userId, loggedInUserId} = req.query;
 188→    if(!userId && !loggedInUserId) return res.status(400).json({error: 'userId or loggendUserId is undefined '});
 189→    // console.log(req.query)
 190→    try {
 191→        const followersCountPromise = supabase
 192→        .from('follows')
 193→        .select('*', {count: 'exact', head: true})
 194→        .eq('following_id', userId);
 195→
 196→        const followingCountPromise = supabase
 197→        .from('follows')
 198→        .select('*', {count: 'exact', head: true})
 199→        .eq('follower_id', userId)
 200→
 201→        const isFollowingPromise = supabase
 202→        .from('follows')
 203→        .select('*', {count: 'exact', head: true})
 204→        .eq('follower_id', loggedInUserId)
 205→        .eq('following_id', userId)
 206→
 207→        const [followersCountResult, followingsCountResult, isFollowingResult] = await Promise.all([
 208→            followersCountPromise, followingCountPromise, isFollowingPromise,
 209→        ])
 210→
 211→
 212→        const {count: followersCount, error: errorFollowers } = followersCountResult;
 213→        const {count: followingsCount, error: errorFollowings} = followingsCountResult;
 214→        const {count: isFollowingCount, error: errorIsfollowing} = isFollowingResult;
 215→
 216→        if(errorFollowers || errorFollowings || errorIsfollowing){
 217→            console.error('supabase error while fetching data:', errorFollowers.message, errorFollowings.message, errorIsfollowing.message)
 218→            return res.status(500).json({error: 'failed to fetch data'})
 219→        }
 220→
 221→        return res.status(200).json({
 222→            followersCount: followersCount,
 223→            followingsCount: followingsCount,
 224→            isFollowing: isFollowingCount > 0
 225→        })
 226→
 227→    } catch (error) {
 228→        console.error('Error in Promise.all:', error);
 229→        res.status(500).json({ error: 'An unexpected error occurred' });
 230→    }
 231→
 232→})
