 393→        users!sender_id(name, user_email, image_url, id, badge)
 394→        `)
 395→    .eq('receiver_id', receiverId)
 396→    .eq('read', false)
 397→    .order('created_at', {ascending: false})
 398→    .order('id', {ascending: false})
 399→    .limit(fetchLimit)
