 423→        return res.status(500).json({error: 'supabase error while getting unread notification'})
 424→    }
 425→    if(opinionResult.error){
 426→        console.error('supabase error:', opinionResult.error.message);
 427→        return res.status(500).json({error: 'supabase error while getting unread opinion notification'})
 428→    }
 429→
 430→    const journalNotifs = (journalResult.data || []).map(n => ({...n, source: 'journal'}));
 431→    const opinionNotifs = (opinionResult.data || []).map(n => ({...n, source: 'opinion'}));
 432→
 433→    const merged = [...journalNotifs, ...opinionNotifs]
 434→        .sort((a, b) => new Date(b.created_at) - new Date(a.created_at));
 435→
 436→    const journalIds = merged.filter(n => n.source === 'journal').map(n => n.journal_id);
 437→
 438→    let hasLikedResult = [];
