141→const extractFromLexical = (contentJson) => {
142→    try {
143→        const parsed = typeof contentJson === 'string' ? JSON.parse(contentJson) : contentJson;
144→        const texts = [];
145→        let firstImage = null;
146→
147→        const walk = (node) => {
148→            if (!node || typeof node !== 'object') return;
149→
150→            const nodeType = String(node.type || node.__type || '').trim().toLowerCase();
151→            if (nodeType === 'text' && typeof node.text === 'string') {
152→                texts.push(node.text);
153→            }
154→
155→            const isImageNode = nodeType === 'image' || nodeType.endsWith('image') || nodeType.includes('image');
156→            if (!firstImage && isImageNode) {
157→                const image = imageFromNodeLike(node);
158→                if (image) {
159→                    firstImage = image;
160→                }
161→            }
162→
163→            if (Array.isArray(node.children)) {
164→                node.children.forEach(walk);
165→            }
166→        };
167→
168→        if (parsed?.root) {
169→            walk(parsed.root);
170→        }
171→
172→        return {
173→            text: normalizeWhitespace(texts.join(' ')),
174→            image: firstImage
175→        };
176→    } catch {
177→        return { text: '', image: null };
178→    }
