295→const isSafeRemoteImageUrl = (imageUrl) => {
296→    try {
297→        const parsed = new URL(imageUrl);
298→        if (parsed.protocol !== 'http:' && parsed.protocol !== 'https:') {
299→            return false;
300→        }
301→
302→        const hostname = parsed.hostname.toLowerCase();
303→        if (!hostname || hostname === 'localhost' || hostname.endsWith('.local') || hostname.endsWith('.internal')) {
304→            return false;
305→        }
306→
307→        if (net.isIP(hostname) && isPrivateIpAddress(hostname)) {
308→            return false;
309→        }
310→
311→        return true;
312→    } catch {
313→        return false;
314→    }
315→};
