### 5. REACT QUERY PATTERNS (client/src/utils/useMutation.js)

**Core Mutation Hooks:**

**useLikeMutation:**
```javascript
export const useLikeMutation = (session, userId) =>{
    const queryClient = useQueryClient();
    const inFlightLikeIdsRef = useRef(new Set());  // De-duplication

    const mutation = useMutation({
        mutationFn: (data) => clickLike(session?.access_token, data),
        onMutate: async(data) => {
            queryClient.cancelQueries({ queryKey: ['journals'] });

            // Snapshot previous data
            const previousData = [
                ...queryClient.getQueriesData({ queryKey: ['journals'] }),
                ...queryClient.getQueriesData({ queryKey: ['userJournals'] }),
            ];

            // Optimistic update
            const updater = (journal) => {
                if(journal.id !== data.journalId) return journal;
                const isLiked = normalizeInteractionFlag(journal?.has_liked);
                const count = normalizeCount(journal?.like_count?.[0]?.count);
                return {
                    ...journal,
                    has_liked: !isLiked,
                    like_count: [{count: isLiked ? count - 1 : count + 1}]
                };
            };

            queryClient.setQueriesData({ queryKey: ['journals'] }, (old) => updateInfiniteJournalsCache(old, updater));
            return {previousData};
        },
        onError: (err, data, context) => {
            context?.previousData?.forEach(([key, value]) => {
                queryClient.setQueryData(key, value);
            });
        },
        onSettled: () => {
            queryClient.invalidateQueries({ queryKey: ['journals'] });
        }
    });

    // Guard against duplicate requests
    const guardedMutate = (variables, options) => {
        const journalKey = toJournalKey(variables?.journalId);
        if(journalKey && inFlightLikeIdsRef.current.has(journalKey)) return;
        inFlightLikeIdsRef.current.add(journalKey);
        mutation.mutate(variables, {
            ...options,
            onSettled: (...args) => {
                inFlightLikeIdsRef.current.delete(journalKey);
                options?.onSettled?.(...args);
            }
        });
    };

    return { ...mutation, mutate: guardedMutate };
}
```

**useBookMarkMutation:** Identical pattern to useLikeMutation

**useFollowMutation:** Simpler pattern, updates single object
```javascript
export const useFollowMutation = (session) =>{
    const queryClient = useQueryClient();
    return useMutation({
        mutationFn: (data) => addFollows(data, session?.access_token),
        onMutate: async(data) => {
            const previousData = queryClient.getQueryData(['followsData']);
            queryClient.setQueryData(['followsData'], (old) => ({
                ...old,
                followersCount: old.isFollowing ? old.followersCount - 1 : old.followersCount + 1,
                isFollowing: !old.isFollowing
            }));
            return {previousData};
        },
        onError: (err, data, context) => {
            queryClient.setQueryData(['followsData'], context.previousData)
        },
        onSettled: () => queryClient.invalidateQueries(['followsData'])
    })
}
```

**Key Helpers:**
```javascript
const updateInfiniteJournalsCache = (old, updater) => {
    if (!old || !Array.isArray(old.pages)) return old;
    return {
        ...old,
        pages: old.pages.map((page) => ({
            ...page,
            data: Array.isArray(page?.data) ? page.data.map(updater) : page?.data,
        })),
    };
};

const normalizeInteractionFlag = (value) => {
    if(typeof value === 'boolean') return value;
    const normalized = String(value).trim().toLowerCase();
    if(normalized === 'true') return true;
    if(normalized === 'false') return false;
    return value === 1;
};

const normalizeCount = (value) => {
    const number = Number(value);
    return (!Number.isFinite(number) || number < 0) ? 0 : number;
};
```

