    font-weight: 500;
    white-space: nowrap;
    flex-shrink: 0;
}

.chapter-manager-item-title {
    font-size: 0.9rem;
    color: var(--text-primary);
    font-weight: 500;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    flex: 1;
    min-width: 0;
}

.chapter-manager-item-words {
    font-size: 0.72rem;
    color: var(--text-muted);
    white-space: nowrap;
    flex-shrink: 0;
}

.chapter-manager-item-actions {
    display: flex;
    align-items: center;
    gap: 6px;
    flex-shrink: 0;
}

.chapter-status-toggle {
    padding: 4px 10px;
    border-radius: 20px;
    border: none;
    font-size: 0.7rem;
    font-weight: 500;
    cursor: pointer;
    transition: background-color 0.12s ease;
    text-transform: uppercase;
    letter-spacing: 0.3px;
}

.chapter-status-published {
    background: rgba(76, 175, 80, 0.12);
    color: #4caf50;
}

.chapter-status-published:hover {
    background: rgba(76, 175, 80, 0.2);
}

.chapter-status-draft {
    background: rgba(158, 158, 158, 0.12);
    color: var(--text-muted);
}

.chapter-status-draft:hover {
    background: rgba(158, 158, 158, 0.2);
}

@media (max-width: 480px) {
    .chapter-manager {
        padding: 16px 12px;
    }

    .chapter-manager-item-content {
        flex-wrap: wrap;
        gap: 4px;
    }

    .chapter-manager-item-words {
        width: 100%;
        margin-left: 0;
    }

    .chapter-manager-edit-story-btn {
        padding: 6px 10px;
        font-size: 0.75rem;
    }
}

