        ]);

        hasVoted = !!voteRes.data;
        inLibrary = !!libRes.data;
        readingProgress = progressRes.data || null;
    }

    return {
        ...story,
        users: authorMap[story.author_id] || null,
        chapters: visibleChapters,
        has_voted: hasVoted,
        in_library: inLibrary,
        reading_progress: readingProgress,
        is_author: isAuthor,
    };
};

