    const handleDeleteChapter = (e, chapter) => {
        e.stopPropagation();
        if (window.confirm(`Delete "${chapter.title}"? This cannot be undone.`)) {
            deleteChapter.mutate({ storyId, chapterId: chapter.id });
        }
    };

    // Drag & drop reorder
    const handleDragStart = useCallback((idx) => {
        setDraggedIdx(idx);
    }, []);

