                        {hasProgress ? 'Continue Reading' : 'Start Reading'}
                    </button>
                )}
                <button
                    className={`story-detail-vote-btn ${story.has_voted ? 'story-detail-vote-btn-active' : ''}`}
                    onClick={handleVote}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill={story.has_voted ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
                        <path d="M12 21.35l-1.45-1.32C5.4 15.36 2 12.28 2 8.5 2 5.42 4.42 3 7.5 3c1.74 0 3.41.81 4.5 2.09C13.09 3.81 14.76 3 16.5 3 19.58 3 22 5.42 22 8.5c0 3.78-3.4 6.86-8.55 11.54L12 21.35z"/>
                    </svg>
                    {story.vote_count || 0}
                </button>
                <button
                    className={`story-detail-library-btn ${story.in_library ? 'story-detail-library-btn-active' : ''}`}
                    onClick={handleLibrary}
                >
                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill={story.in_library ? 'currentColor' : 'none'} stroke="currentColor" strokeWidth="2">
                        <path d="M19 21l-7-5-7 5V5a2 2 0 0 1 2-2h10a2 2 0 0 1 2 2z"/>
                    </svg>
                    {story.in_library ? 'In Library' : 'Add to Library'}
                </button>
            </div>

            {/* Description */}
            {story.description && (
                <div className="story-detail-description">
                    <h3>About</h3>
                    <p>{story.description}</p>
                </div>
            )}

            {/* Chapter list */}
            <div className="story-detail-chapters">
                <h3>Chapters ({chapters.length})</h3>
                {chapters.length === 0 ? (
                    <p className="story-detail-no-chapters">No chapters published yet.</p>
                ) : (
                    <div className="story-detail-chapter-list">
                        {chapters.map((ch) => (
                            <div
                                key={ch.id}
                                className="story-detail-chapter-item"
                                onClick={() => navigate(`/home/stories/${storyId}/chapter/${ch.id}`)}
                            >
                                <div className="story-detail-chapter-left">
                                    <span className="story-detail-chapter-number">Ch. {ch.chapter_number}</span>
                                    <span className="story-detail-chapter-title">{ch.title}</span>
                                </div>
                                <div className="story-detail-chapter-right">
                                    <span className="story-detail-chapter-words">{(ch.word_count || 0).toLocaleString()} words</span>
                                </div>
                            </div>
                        ))}
                    </div>
                )}
            </div>
        </motion.div>
    );
};

export default StoryDetail;

