              </Route>  
            </Route>   

            <Route path='/universe' element={<Universe/>}/>

            <Route path='/login' element={<LoginPage/>}/>
            <Route path='/signUp' element={<SignUp/>}/>
          </Routes>
        </Suspense>
      </BrowserRouter>
    </LexicalComposer>
    </>
  )
}

export default App

