            .from('stories')
            .select('read_count')
            .eq('id', storyId)
            .single();
        if (story) {
            await supabase
                .from('stories')
                .update({ read_count: (story.read_count || 0) + 1 })
                .eq('id', storyId);
        }
    }

    return data;
};

