    flex-shrink: 0;
}

.chapter-editor-back:hover {
    background: var(--bg-hover);
}

.chapter-editor-title-input {
    flex: 1;
    border: none;
    background: none;
    font-size: 1.1rem;
    font-weight: 600;
    color: var(--text-primary);
    outline: none;
    font-family: inherit;
    padding: 6px 4px;
