 85→export const imageUploader = async(file, userId, bucket) =>{
 86→    if(!file){
 87→        return res.status(500).json({error: 'no file received'});
 88→    }
 89→
 90→    let img_buffer = null
 91→    let img_url = null
 92→    img_buffer = await sharp(file.buffer)
 93→    .webp({quality: 80})
 94→    .toBuffer();
 95→
 96→    const folderName = `user_id_${userId}`;
 97→    const fileName = `${Date.now()}_${crypto.randomUUID()}.webp`;
 98→    const filePath = `${folderName}/${fileName}`;
 99→
100→    const {data: uploadImage, error: errorUploadImage} = await supabase.storage
101→    .from(bucket)
102→    .upload(filePath, img_buffer, {
103→        contentType: 'image/webp',
104→        upsert: true
105→    })
106→    if(errorUploadImage){
107→        console.error('supabase error while uploading image to supabase bucket', errorUploadImage)
108→        return res.status(500).json({error: 'error uploading image into supabase bucket'});
109→    }
110→    const {data: data_url} = supabase.storage
111→    .from(bucket)
112→    .getPublicUrl(filePath)
113→    
114→    if(data_url){
115→        img_url = data_url.publicUrl;
116→        return img_url;
117→    } else {
118→        throw new Error('Error uploading the image');
119→    }
120→}
