216→export const saveProgressService = async (storyId, userId, chapterId, scrollPosition) => {
217→    if (!storyId || !userId || !chapterId) {
218→        throw { status: 400, error: 'storyId, userId, and chapterId are required' };
219→    }
220→
221→    // Check if this is a new reader (no existing progress for this user+story)
222→    const { data: existing } = await supabase
223→        .from('reading_progress')
224→        .select('id')
225→        .eq('user_id', userId)
226→        .eq('story_id', storyId)
227→        .maybeSingle();
228→
229→    const { data, error } = await supabase
230→        .from('reading_progress')
231→        .upsert({
232→            user_id: userId,
233→            story_id: storyId,
234→            chapter_id: chapterId,
235→            scroll_position: scrollPosition || 0,
236→            last_read_at: new Date().toISOString(),
237→        }, { onConflict: 'user_id,story_id' })
238→        .select('*')
239→        .single();
240→
241→    if (error) {
242→        console.error('supabase error saving progress:', error.message);
243→        throw { status: 500, error: 'failed to save progress' };
244→    }
245→
246→    // Increment read_count if this is a new reader (skip if author)
247→    if (!existing) {
248→        const { data: story } = await supabase
249→            .from('stories')
250→            .select('author_id')
251→            .eq('id', storyId)
252→            .single();
253→
254→        if (story && story.author_id !== userId) {
255→            const { error: rpcError } = await supabase.rpc('increment_story_reads', { story_id_input: storyId });
256→            if (rpcError) {
257→                console.error('error incrementing story reads:', rpcError.message);
258→            }
259→        }
260→    }
261→
262→    return data;
263→};
