    const isMobile = useMediaQuery('(max-width: 768px)'); // or use window.innerWidth check

    const { data: comments, isLoading } = useChapterComments(chapterId, paragraphIndex, token);
    const addComment = useAddChapterComment(token);

    const handleSubmit = async () => {
        const trimmed = commentText.trim();
        if (!trimmed || trimmed.length > 300) return;

        // Optimistic update
        const optimistic = {
            id: `optimistic-${Date.now()}`,
            comment: trimmed,
            created_at: new Date().toISOString(),
            paragraph_index: paragraphIndex,
            parent_id: replyTarget?.id || null,
            users: {
                id: user?.userData?.[0]?.id,
                name: user?.userData?.[0]?.name,
                image_url: user?.userData?.[0]?.image_url,
                badge: user?.userData?.[0]?.badge,
            },
            replies: [],
        };

        queryClient.setQueryData(
            ['chapterComments', chapterId, paragraphIndex],
            (old) => replyTarget
                ? old.map(c => c.id === replyTarget.id
                    ? { ...c, replies: [...(c.replies || []), optimistic] }
                    : c)
                : [...(old || []), optimistic]
        );

        // Optimistically increment count
        queryClient.setQueryData(
            ['chapterCommentCounts', chapterId],
            (old) => ({
                ...old,
                [String(paragraphIndex)]: ((old?.[String(paragraphIndex)] || 0) + 1),
            })
        );

        try {
            await addComment.mutateAsync({
                chapterId,
                data: {
                    comment: trimmed,
                    paragraph_index: paragraphIndex,
                    paragraph_fingerprint: paragraphFingerprint,
                    parent_id: replyTarget?.id || null,
                },
            });
            setCommentText('');
            setReplyTarget(null);
