                    <button className="cp-close-btn" onClick={onClose}>
                        {/* X icon SVG */}
                    </button>
                </div>

                {/* Paragraph preview */}
                <div className="cp-paragraph-preview">
                    <div className="cp-preview-accent-bar" />
                    <p className="cp-preview-text">{paragraphText}</p>
                </div>

                {/* Comment list */}
                <div className="cp-comment-list">
                    {isLoading ? (
                        <div className="cp-loading">
                            <MoonLoader size={18} color="var(--loader-color)" />
